// ── Layer 2 dedup (n8n-side) ──────────────────────────────────────────────
// Layer 1 is on the server (notification_sent flag). This layer catches the
// edge case where the server crashed after firing the webhook but before
// persisting notification_sent=1, so it retried — we must not deliver twice.

const sessionId = $input.first().json.body?.sessionId ?? $input.first().json.sessionId;

if (!sessionId) {
  throw new Error('Missing sessionId in webhook payload');
}

// Static workflow data persists across executions (stored in n8n SQLite)
const state = $getWorkflowStaticData('global');
if (!state.processedSessions) state.processedSessions = {};

if (state.processedSessions[sessionId]) {
  // Already processed — return empty to stop execution
  console.log('[dedup] Session already processed, skipping:', sessionId);
  return [];
}

// Pass through with the original payload
return [{ json: $input.first().json.body ?? $input.first().json }];

// Mark this sessionId as processed so future replays are skipped (Layer 2 dedup)
const sessionId = $('Dedup Check').first().json.sessionId;

const state = $getWorkflowStaticData('global');
if (!state.processedSessions) state.processedSessions = {};
state.processedSessions[sessionId] = Date.now();

console.log('[dedup] Marked as processed:', sessionId);
return [{ json: { ok: true, markedDone: sessionId } }];
